   453→void
   454→ber_reset( BerElement *ber, int was_writing )
   455→{
   456→	assert( ber != NULL );
   457→	assert( LBER_VALID( ber ) );
   458→
   459→	if ( was_writing ) {
   460→		ber->ber_end = ber->ber_ptr;
   461→		ber->ber_ptr = ber->ber_buf;
   462→
   463→	} else {
   464→		ber->ber_ptr = ber->ber_end;
   465→	}
   466→
   467→	ber->ber_rwptr = NULL;
   468→}
   469→
   470→/*
   471→ * A rewrite of ber_get_next that can safely be called multiple times 
   472→ * for the same packet. It will simply continue where it stopped until
   473→ * a full packet is read.
   474→ */
   475→
   476→#define LENSIZE	4
   477→
   478→ber_tag_t
   479→ber_get_next(
   480→	Sockbuf *sb,
   481→	ber_len_t *len,
   482→	BerElement *ber )
   483→{
   484→	assert( sb != NULL );
   485→	assert( len != NULL );
   486→	assert( ber != NULL );
   487→	assert( SOCKBUF_VALID( sb ) );
   488→	assert( LBER_VALID( ber ) );
   489→
   490→	if ( ber->ber_debug & LDAP_DEBUG_TRACE ) {
   491→		ber_log_printf( LDAP_DEBUG_TRACE, ber->ber_debug,
   492→			"ber_get_next\n" );
   493→	}
   494→
   495→	/*
   496→	 * Any ber element looks like this: tag length contents.
   497→	 * Assuming everything's ok, we return the tag byte (we
   498→	 * can assume a single byte), return the length in len,
   499→	 * and the rest of the undecoded element in buf.
   500→	 *
   501→	 * Assumptions:
   502→	 *	1) small tags (less than 128)
   503→	 *	2) definite lengths
   504→	 *	3) primitive encodings used whenever possible
   505→	 *
   506→	 * The code also handles multi-byte tags. The first few bytes
   507→	 * of the message are read to check for multi-byte tags and
   508→	 * lengths. These bytes are temporarily stored in the ber_tag,
   509→	 * ber_len, and ber_usertag fields of the berelement until
   510→	 * tag/len parsing is complete. After this parsing, any leftover
   511→	 * bytes and the rest of the message are copied into the ber_buf.
   512→	 *
   513→	 * We expect tag and len to be at most 32 bits wide.
   514→	 */
   515→
   516→	if (ber->ber_rwptr == NULL) {
   517→		assert( ber->ber_buf == NULL );
   518→		ber->ber_rwptr = (char *) &ber->ber_len-1;
   519→		ber->ber_ptr = ber->ber_rwptr;
   520→		ber->ber_tag = 0;
   521→	}
   522→
   523→	while (ber->ber_rwptr > (char *)&ber->ber_tag && ber->ber_rwptr <
   524→		(char *)&ber->ber_len + LENSIZE*2) {
   525→		ber_slen_t sblen;
   526→		char buf[sizeof(ber->ber_len)-1];
   527→		ber_len_t tlen = 0;
   528→
   529→		/* The tag & len can be at most 9 bytes; we try to read up to 8 here */
   530→		sock_errset(0);
   531→		sblen=((char *)&ber->ber_len + LENSIZE*2 - 1)-ber->ber_rwptr;
   532→		/* Trying to read the last len byte of a 9 byte tag+len */
   533→		if (sblen<1)
   534→			sblen = 1;
   535→		sblen=ber_int_sb_read( sb, ber->ber_rwptr, sblen );
   536→		if (sblen<=0) return LBER_DEFAULT;
   537→		ber->ber_rwptr += sblen;
   538→
   539→		/* We got at least one byte, try to parse the tag. */
   540→		if (ber->ber_ptr == (char *)&ber->ber_len-1) {
   541→			ber_tag_t tag;
   542→			unsigned char *p = (unsigned char *)ber->ber_ptr;
   543→			tag = *p++;
   544→			if ((tag & LBER_BIG_TAG_MASK) == LBER_BIG_TAG_MASK) {
   545→				ber_len_t i;
   546→				for (i=1; (char *)p<ber->ber_rwptr; i++) {
   547→					tag <<= 8;
   548→					tag |= *p++;
   549→					if (!(tag & LBER_MORE_TAG_MASK))
   550→						break;
   551→					/* Is the tag too big? */
   552→					if (i == sizeof(ber_tag_t)-1) {
   553→						sock_errset(ERANGE);
   554→						return LBER_DEFAULT;
   555→					}
   556→				}
   557→				/* Did we run out of bytes? */
   558→				if ((char *)p == ber->ber_rwptr) {
   559→					sock_errset(EWOULDBLOCK);
   560→					return LBER_DEFAULT;
   561→				}
   562→			}
   563→			ber->ber_tag = tag;
   564→			ber->ber_ptr = (char *)p;
   565→		}
   566→
   567→		if ( ber->ber_ptr == ber->ber_rwptr ) {
   568→			sock_errset(EWOULDBLOCK);
   569→			return LBER_DEFAULT;
   570→		}
   571→
   572→		/* Now look for the length */
   573→		if (*ber->ber_ptr & 0x80) {	/* multi-byte */
   574→			int i;
   575→			unsigned char *p = (unsigned char *)ber->ber_ptr;
   576→			int llen = *p++ & 0x7f;
   577→			if (llen > LENSIZE) {
   578→				sock_errset(ERANGE);
   579→				return LBER_DEFAULT;
   580→			}
   581→			/* Not enough bytes? */
   582→			if (ber->ber_rwptr - (char *)p < llen) {
   583→				sock_errset(EWOULDBLOCK);
   584→				return LBER_DEFAULT;
   585→			}
   586→			for (i=0; i<llen; i++) {
   587→				tlen <<=8;
   588→				tlen |= *p++;
   589→			}
   590→			ber->ber_ptr = (char *)p;
   591→		} else {
   592→			tlen = *(unsigned char *)ber->ber_ptr++;
   593→		}
   594→
   595→		/* Are there leftover data bytes inside ber->ber_len? */
   596→		if (ber->ber_ptr < (char *)&ber->ber_usertag) {
   597→			if (ber->ber_rwptr < (char *)&ber->ber_usertag) {
   598→				sblen = ber->ber_rwptr - ber->ber_ptr;
   599→			} else {
   600→				sblen = (char *)&ber->ber_usertag - ber->ber_ptr;
   601→			}
   602→			AC_MEMCPY(buf, ber->ber_ptr, sblen);
   603→			ber->ber_ptr += sblen;
   604→		} else {
   605→			sblen = 0;
   606→		}
   607→		ber->ber_len = tlen;
   608→
   609→		/* now fill the buffer. */
   610→
   611→		/* make sure length is reasonable */
   612→		if ( ber->ber_len == 0 ) {
   613→			sock_errset(ERANGE);
   614→			return LBER_DEFAULT;
   615→		}
   616→
   617→		if ( sb->sb_max_incoming && ber->ber_len > sb->sb_max_incoming ) {
   618→			ber_log_printf( LDAP_DEBUG_CONNS, ber->ber_debug,
   619→				"ber_get_next: sockbuf_max_incoming exceeded "
   620→				"(%ld > %ld)\n", ber->ber_len, sb->sb_max_incoming );
   621→			sock_errset(ERANGE);
   622→			return LBER_DEFAULT;
   623→		}
   624→
   625→		if (ber->ber_buf==NULL) {
   626→			ber_len_t l = ber->ber_rwptr - ber->ber_ptr;
   627→			/* ber->ber_ptr is always <= ber->ber->ber_rwptr.
   628→			 * make sure ber->ber_len agrees with what we've
   629→			 * already read.
   630→			 */
   631→			if ( ber->ber_len < sblen + l ) {
   632→				sock_errset(ERANGE);
   633→				return LBER_DEFAULT;
   634→			}
   635→			ber->ber_buf = (char *) ber_memalloc_x( ber->ber_len + 1, ber->ber_memctx );
   636→			if (ber->ber_buf==NULL) {
   637→				return LBER_DEFAULT;
   638→			}
   639→			ber->ber_end = ber->ber_buf + ber->ber_len;
   640→			if (sblen) {
   641→				AC_MEMCPY(ber->ber_buf, buf, sblen);
   642→			}
   643→			if (l > 0) {
   644→				AC_MEMCPY(ber->ber_buf + sblen, ber->ber_ptr, l);
   645→				sblen += l;
   646→			}
   647→			*ber->ber_end = '\0';
   648→			ber->ber_ptr = ber->ber_buf;
   649→			ber->ber_usertag = 0;
   650→			if ((ber_len_t)sblen == ber->ber_len) {
   651→				goto done;
   652→			}
   653→			ber->ber_rwptr = ber->ber_buf + sblen;
   654→		}
   655→	}
   656→
   657→	if ((ber->ber_rwptr>=ber->ber_buf) && (ber->ber_rwptr<ber->ber_end)) {
   658→		ber_slen_t res;
   659→		ber_slen_t to_go;
   660→		
   661→		to_go = ber->ber_end - ber->ber_rwptr;
   662→		/* unsigned/signed overflow */
   663→		if (to_go<0) return LBER_DEFAULT;
   664→		
   665→		sock_errset(0);
   666→		res = ber_int_sb_read( sb, ber->ber_rwptr, to_go );
   667→		if (res<=0) return LBER_DEFAULT;
   668→		ber->ber_rwptr+=res;
   669→		
   670→		if (res<to_go) {
   671→			sock_errset(EWOULDBLOCK);
   672→			return LBER_DEFAULT;
   673→		}
   674→done:
   675→		ber->ber_rwptr = NULL;
   676→		*len = ber->ber_len;
   677→		if ( ber->ber_debug ) {
   678→			ber_log_printf( LDAP_DEBUG_TRACE, ber->ber_debug,
   679→				"ber_get_next: tag 0x%lx len %ld contents:\n",
   680→				ber->ber_tag, ber->ber_len );
   681→			ber_log_dump( LDAP_DEBUG_BER, ber->ber_debug, ber, 1 );
   682→		}
   683→		return (ber->ber_tag);
   684→	}
   685→
   686→	/* invalid input */
   687→	return LBER_DEFAULT;
   688→}
   689→
   690→char *
   691→ber_start( BerElement* ber )
   692→{
   693→	return ber->ber_buf;
   694→}
   695→
   696→int
   697→ber_len( BerElement* ber )
   698→{
   699→	return ( ber->ber_end - ber->ber_buf );
   700→}
   701→
   702→int
   703→ber_ptrlen( BerElement* ber )
   704→{
   705→	return ( ber->ber_ptr - ber->ber_buf );
   706→}
   707→
   708→void
   709→ber_rewind ( BerElement * ber )
   710→{
   711→	ber->ber_rwptr = NULL;
   712→	ber->ber_sos_ptr = NULL;
   713→	ber->ber_end = ber->ber_ptr;
   714→	ber->ber_ptr = ber->ber_buf;
   715→#if 0	/* TODO: Should we add this? */
   716→	ber->ber_tag = LBER_DEFAULT;
   717→	ber->ber_usertag = 0;
   718→#endif
   719→}
   720→
   721→int
   722→ber_remaining( BerElement * ber )
   723→{
   724→	return ber_pvt_ber_remaining( ber );
